insert into public.platform_jurisdiction_standards (
  id,
  jurisdiction_code,
  surface_scope,
  standard_type,
  title,
  summary,
  applicability,
  content,
  source_url,
  source_title,
  source_authority,
  effective_date,
  last_reviewed_date,
  metadata
)
values
('std_federal_baseline', 'federal', 'both', 'osha_ref', 'Federal OSHA construction baseline', 'Use federal OSHA 29 CFR Part 1926 as the baseline construction profile when the selected state is not covered by a state-plan delta.', '{}'::jsonb, '{"body":"Federal OSHA remains the baseline construction standard set for CSEP and PESHEP unless a selected OSHA-approved State Plan introduces additional or different requirements that must be layered into the draft and review workflow.","bullets":["Confirm project planning addresses housekeeping, training, first aid, emergency response, and PPE expectations from the federal construction baseline.","When a selected state does not have a seeded state-plan delta, keep the federal baseline active and flag the draft as federal OSHA."],"oshaRefs":["29 CFR 1926 Subpart C - General Safety and Health Provisions","29 CFR 1926.20 - General safety and health provisions","29 CFR 1926.21 - Safety training and education","29 CFR 1926.23 - First aid and medical attention","29 CFR 1926.25 - Housekeeping","29 CFR 1926.28 - Personal protective equipment","29 CFR 1926.35 - Employee emergency action plans"],"builderGuidance":"Apply the federal OSHA construction baseline unless the governing state resolves to a seeded state-plan jurisdiction.","adminReviewNote":"This draft uses the federal OSHA baseline profile."}'::jsonb, 'https://www.osha.gov/laws-regs/regulations/standardnumber/1926/1926SubpartC', '1926 Subpart C - General Safety and Health Provisions', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb),
('std_federal_training_emergency', 'federal', 'peshep', 'training_requirement', 'Federal training and emergency planning baseline', 'PESHEP drafts should explicitly address training, emergency posting, and reporting controls expected under the federal construction baseline.', '{}'::jsonb, '{"trainingNotes":["Confirm workforce safety training expectations are written into the project plan.","Document emergency contacts, response flow, and treatment resources before mobilization."],"checklist":{"requiredFields":["incident_reporting_process_text","inspection_process_text","posted_emergency_contacts_text"],"note":"Federal baseline planning expects training, emergency communication, and reporting coverage in site-level safety documentation."}}'::jsonb, 'https://www.osha.gov/stateplans', 'State Plans', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb),
('std_ca_iipp_review', 'ca', 'both', 'admin_review_note', 'California state-plan review note', 'California drafts should be reviewed against current Cal/OSHA Title 8 requirements and the project''s written safety program expectations.', '{}'::jsonb, '{"body":"California operates an OSHA-approved State Plan through Cal/OSHA. Reviewers should confirm that the draft aligns with current Cal/OSHA expectations, including project-specific written safety management requirements and any applicable Title 8 construction orders.","builderGuidance":"Show the draft as a California state-plan profile and direct reviewers to confirm current Cal/OSHA-specific requirements before release.","adminReviewNote":"California state-plan delta active. Verify current Cal/OSHA / Title 8 alignment before approval.","checklist":{"requiredFields":["site_specific_notes","inspection_process_text"],"note":"California drafts should clearly show how project-specific safety expectations and inspections will be managed."}}'::jsonb, 'https://dir.ca.gov/dosh/', 'Cal/OSHA - Division of Occupational Safety and Health - Home Page', 'California Department of Industrial Relations / Cal/OSHA', null, '2026-04-15'::date, '{}'::jsonb),
('std_ca_construction_orders', 'ca', 'csep', 'program_requirement', 'California construction-orders overlay', 'CSEP program sections for California should explicitly tell reviewers to reconcile controls and references against current Cal/OSHA construction orders.', '{}'::jsonb, '{"oshaRefs":["California Code of Regulations, Title 8 - Construction Safety Orders"],"requiredControls":["Verify the selected construction controls against the current Cal/OSHA construction-order language before final issue.","Document any project-specific California safety-program expectations in the contractor handoff notes."]}'::jsonb, 'https://www.osha.gov/stateplans/ca', 'California State Plan', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb),
('std_wa_construction_rules', 'wa', 'both', 'builder_prompt_delta', 'Washington construction-rules overlay', 'Washington drafts should call out DOSH / WAC 296-155 construction rules as an active state-plan overlay.', '{}'::jsonb, '{"body":"Washington DOSH has adopted most OSHA standards by reference but also maintains unique state-plan construction rules in areas including fall protection, excavation, rigging, storage of materials, signs and barricades, and other core construction controls.","oshaRefs":["WAC 296-155 - Safety Standards for Construction Work"],"adminReviewNote":"Washington state-plan delta active. Verify WAC 296-155 construction requirements before approval."}'::jsonb, 'https://www.osha.gov/stateplans/wa', 'Washington State Plan', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb),
('std_wa_excavation', 'wa', 'csep', 'permit_requirement', 'Washington excavation and trenching emphasis', 'Washington excavation-related scopes should reinforce trenching, shoring, and competent-person expectations from the DOSH construction rules.', '{}'::jsonb, '{"requiredControls":["Confirm excavation, trenching, and shoring controls against current Washington DOSH construction requirements before field issue.","Identify the competent-person review path for trench conditions, utilities, and protective systems in the project handoff."],"trainingNotes":["Ensure excavation crews understand Washington-specific trenching and competent-person expectations."]}'::jsonb, 'https://lni.wa.gov/safety-health/safety-topics/topics/trenching-excavation', 'Trenching & Excavation', 'Washington State Department of Labor & Industries', null, '2026-04-15'::date, '{}'::jsonb),
('std_or_state_plan', 'or', 'both', 'admin_review_note', 'Oregon state-plan review note', 'Oregon drafts should be reviewed against Oregon OSHA construction requirements and any Oregon-specific adoption updates before release.', '{}'::jsonb, '{"body":"Oregon operates an OSHA-approved State Plan through Oregon OSHA. Reviewers should confirm that the draft aligns with Oregon OSHA construction requirements and any Oregon-specific adoption updates that affect the selected work.","adminReviewNote":"Oregon state-plan delta active. Verify Oregon OSHA construction alignment before approval."}'::jsonb, 'https://www.osha.gov/stateplans/or', 'Oregon State Plan', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb),
('std_or_rules_resources', 'or', 'peshep', 'builder_prompt_delta', 'Oregon rules and laws workflow note', 'Oregon PESHEP drafts should explicitly tell admins to reconcile recurring inspections and site controls with Oregon OSHA rules and laws resources.', '{}'::jsonb, '{"checklist":{"requiredFields":["inspection_process_text","event_calendar_notes_text"],"note":"Oregon review should confirm that inspections and recurring compliance events are written into the site plan."}}'::jsonb, 'https://osha.oregon.gov/', 'Oregon OSHA Home', 'State of Oregon / Oregon OSHA', null, '2026-04-15'::date, '{}'::jsonb),
('std_mi_state_plan', 'mi', 'both', 'builder_prompt_delta', 'Michigan MIOSHA standards overlay', 'Michigan drafts should identify MIOSHA construction standards as an active state-plan overlay instead of relying only on federal citations.', '{}'::jsonb, '{"body":"Michigan operates an OSHA-approved State Plan through MIOSHA. Construction drafts should be reviewed against current MIOSHA construction safety and health standards, including the applicable administrative rules and updated construction parts.","adminReviewNote":"Michigan state-plan delta active. Verify MIOSHA construction standards before approval."}'::jsonb, 'https://www.michigan.gov/leo/bureaus-agencies/miosha/standards/standards-and-interpretations/construction-safety-and-health-standards', 'Construction Safety and Health Standards', 'Michigan Department of Labor and Economic Opportunity / MIOSHA', null, '2026-04-15'::date, '{}'::jsonb),
('std_mi_cranes_steel', 'mi', 'csep', 'program_requirement', 'Michigan crane and steel-erection emphasis', 'Michigan crane and steel-related CSEP sections should push reviewers to verify the current MIOSHA construction parts that govern the selected lift or steel scope.', '{}'::jsonb, '{"requiredControls":["Verify crane, derrick, steel-erection, and related lift planning controls against the current MIOSHA construction parts before release."],"oshaRefs":["MIOSHA Construction Safety and Health Standards"]}'::jsonb, 'https://www.michigan.gov/leo/bureaus-agencies/miosha/standards/standards-and-interpretations/construction-safety-and-health-standards', 'Construction Safety and Health Standards', 'Michigan Department of Labor and Economic Opportunity / MIOSHA', null, '2026-04-15'::date, '{}'::jsonb),
('std_nc_state_plan', 'nc', 'both', 'admin_review_note', 'North Carolina state-plan review note', 'North Carolina drafts should indicate that the state adopts most federal standards verbatim but still requires review for North Carolina-specific rules and procedures.', '{}'::jsonb, '{"body":"North Carolina generally adopts federal OSHA standards verbatim, but employers must comply with North Carolina-specific rules when the state''s administrative rules differ from federal OSHA. Reviewers should confirm whether state-specific construction rules are triggered by the selected work.","adminReviewNote":"North Carolina state-plan delta active. Check for NC-specific construction rules before approval.","checklist":{"requiredFields":["inspection_process_text","special_conditions_permit_text"],"note":"North Carolina review should document how site-specific rules, variances, and inspections will be managed."}}'::jsonb, 'https://www.labor.nc.gov/safety-and-health/occupational-safety-and-health', 'Occupational Safety and Health', 'North Carolina Department of Labor', null, '2026-04-15'::date, '{}'::jsonb),
('std_nc_construction_specific', 'nc', 'csep', 'program_requirement', 'North Carolina construction-specific standards emphasis', 'North Carolina construction drafts should flag state-specific PPE, steel-erection, blasting, bloodborne-pathogen, and communication-tower standards when those scopes are implicated.', '{}'::jsonb, '{"requiredControls":["If the selected work touches PPE, steel erection, blasting, bloodborne pathogens, or communication towers, verify the applicable North Carolina-specific construction standards before issue."]}'::jsonb, 'https://www.osha.gov/stateplans/NC', 'North Carolina State Plan', 'Occupational Safety and Health Administration (OSHA)', null, '2026-04-15'::date, '{}'::jsonb)
on conflict (id) do update
set
  jurisdiction_code = excluded.jurisdiction_code,
